import squareStatus from '../squareStatus';

export default ({ piece, pieces }) => {
  const shotCastling = piece.player === 'white' ? 31 : 38;
  const longCastling = piece.player === 'white' ? 71 : 78;
  let moves = [
    piece.position - 11,
    piece.position - 10,
    piece.position - 9,
    piece.position - 1,
    piece.position + 1,
    piece.position + 9,
    piece.position + 10,
    piece.position + 11,
  ];

  moves = moves.filter((square) => {
    square = squareStatus({ square, player: piece.player, pieces });

    return square.empty || square.enemy;
  });

  return moves;
};
